inline int maximumSubarray(const std::vector<int>& x) {
    if (x.empty()) return 0;                     // empty array edge‑case
    const int* data = x.data();                  // pointer for fast access
    const std::size_t n = x.size();

    int maxEnding = data[0];                     // best sum ending at current pos
    int maxOverall = data[0];                    // best sum found so far

    for (std::size_t i = 1; i < n; ++i) {
        const int v = data[i];
        /* Kadane’s rule – either continue the current subarray or
           start a new one at this element.  No branching at the
           branch misprediction core.                            */
        maxEnding = std::max(v, maxEnding + v);
        maxOverall = std::max(maxOverall, maxEnding);
    }
    return maxOverall;
}
