 */
int maxDegree(const std::vector<int> &A, size_t N) {
    // If the matrix is too small, just use the simple loop
    if (N < 128) {
        int highest = 0;
        for (size_t i = 0; i < N; ++i) {
            int deg = 0;
            const int *row = &A[i * N];
            for (size_t j = 0; j < N; ++j) {
                deg += row[j];
            }
            if (deg > highest) highest = deg;
        }
        return highest;
    }

    int highest = 0;
    #pragma omp parallel for reduction(max:highest) schedule(static)
    for (int i = 0; i < static_cast<int>(N); ++i) {
        int deg = 0;
        const int *row = &A[i * N];
        for (size_t j = 0; j < N; ++j) {
            deg += row[j];
        }
        if (deg > highest) highest = deg;
    }
    return highest;
}
