// In the vector x negate the odd values and divide the even values by 2.
// Example:
//
// input:  [16, 11, 12, 14, 1, 0, 5]
// output: [8, -11, 6, 7, -1, 0, -5]
//
inline void negateOddsAndHalveEvens(std::vector<int> &x) {
    const std::size_t n = x.size();

    // Parallel loop: no data races because each iteration writes to a distinct element.
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
        const int v = x[static_cast<std::size_t>(i)];
        // Use bitwise check for speed and avoid division on odd numbers.
        if ((v & 1) == 0) {          // even
            x[static_cast<std::size_t>(i)] = v >> 1;  // divide by 2 with arithmetic shift
        } else {                      // odd
            x[static_cast<std::size_t>(i)] = -v;
        }
    }
}
