#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Compute y = alpha*A*x + beta*y where alpha and beta are scalars, x and y are vectors,
   and A is a sparse matrix stored in COO format.
*/
inline void spmv(double alpha,
                 std::vector<COOElement> const& A,
                 std::vector<double> const& x,
                 double beta,
                 std::vector<double> &y,
                 size_t M,
                 size_t N)
{
    /* Scale y by beta in parallel. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < y.size(); ++i) {
        y[i] *= beta;
    }

    /* Perform the sparse matrix‑vector multiplication.
       Each update to y[row] is atomic to avoid race conditions. */
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < A.size(); ++i) {
        const auto& e = A[i];
        if (e.row < M && e.column < N) {
            double tmp = alpha * e.value * x[e.column];
            #pragma omp atomic
            y[e.row] += tmp;
        }
    }
}
