/*
   Compute the reverse prefix sum of vector `x` into `output`.
   Example:
     x      = [1, 7, 4, 6, 6, 2]
     output = [2, 8, 14, 18, 25, 26]
*/
inline void reversePrefixSum(const std::vector<int> &x, std::vector<int> &output)
{
    const std::size_t n = x.size();
    output.resize(n);
    if (n == 0) return;

    /* Perform the scan in the reversed order.
       The loop is split into two phases: a serial warm‑up to
       initialise the first element, followed by a parallel scan
       on the remaining tail.  The inner update is trivial so an
       openmp reduction is not required. */
    output[n-1] = x[n-1];
    #pragma omp parallel for schedule(static)
    for (std::ptrdiff_t i = n-2; i >= 0; --i)
    {
        /* Manually accumulate in reverse order.  The loop
           bounds are managed with ptrdiff_t to handle 32‑bit
           indices correctly. */
        output[i] = output[i+1] + x[i];
    }
}
