/*
 * Compute the ReLU function on every element of x. Elements less than zero become
 * zero, while elements greater than zero stay the same.
 *
 * Example:
 *   input:  [-1.8, 24.0, 1.2, 0.0, -5.1, -0.2, 4.5]
 *   output: [0,   24.0, 1.2, 0,   0,    0,    4.5]
 */
inline void relu(std::vector<double>& x)
{
    const std::size_t n = x.size();
    if (n == 0) return;

    /* Gracefully fall back to a sequential loop when OpenMP is not available
     * or when the vector is small enough that parallel overhead outweighs
     * benefit.                                  */
    const std::size_t min_parallel_size = 1 << 12; // 4096 elements

    if (n < min_parallel_size) {
        for (std::size_t i = 0; i < n; ++i) {
            if (x[i] < 0.0) x[i] = 0.0;
        }
    } else {
        /* Parallelize across threads, each thread processes a chunk of the
         * vector.  The loop body is trivially cheap, so this gives a good
         * speed‑up on large input vectors. */
#pragma omp parallel for schedule(static)
        for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(n); ++i) {
            if (x[i] < 0.0) x[i] = 0.0;
        }
    }
