46_sparse_la_spmm:
```cpp
#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Compute the matrix multiplication Y = A * X.
 * A: sparse M x K matrix in COO format.
 * X: sparse K x N matrix in COO format.
 * Y: dense M x N matrix (row‑major).
 *
 * This implementation uses a hash map to group X by
 * source row and OpenMP to parallelise the outer
 * multiplication loop, giving a substantial speedup on
 * modern multi‑core CPUs.
 */
void spmm(std::vector<COOElement> const& A,
          std::vector<COOElement> const& X,
          std::vector<double> &Y,
          size_t M, size_t K, size_t N)
{
    /* initialise Y */
    Y.assign(M * N, 0.0);

    /* build map: for each row in X, store its non‑zero column/value pairs */
    std::unordered_map<size_t, std::vector<std::pair<size_t,double>>> x_group;
    x_group.reserve(X.size()*2);
    for (const auto& e : X)
        x_group[e.row].emplace_back(e.column, e.value);

    /* parallel outer loop over A */
    #pragma omp parallel for schedule(static)
    for (long long ai = 0; ai < static_cast<long long>(A.size()); ++ai) {
        const auto &a = A[ai];
        auto it = x_group.find(a.column);
        if (it == x_group.end()) continue;            // no contribution

        double a_val = a.value;
        size_t base = a.row * N;
        for (const auto &p : it->second) {
            Y[base + p.first] += a_val * p.second;
        }
    }
}
