#pragma once
#include <array>
#include <vector>
#include <cstddef>
#include <omp.h>

struct Point {
    double x, y;
};

/*
 * Count the number of Cartesian points in each quadrant.
 * points   – input array of Point
 * bins     – output array of size 4, initialized to 0
 *
 * Returns nothing, modifies bins in-place.
 *
 * The function is thread‑safe and preserves the exact semantics of
 * the original single‑threaded implementation.
 */
void countQuadrants(std::vector<Point> const& points, std::array<size_t, 4>& bins) {
    // Ensure bins are zeroed before accumulation
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Local reduction variables per thread to avoid atomics on every hit
    const std::size_t N = points.size();
    if (N == 0) return;

    #pragma omp parallel
    {
        size_t local[4] = {0, 0, 0, 0};

        #pragma omp for nowait
        for (std::size_t i = 0; i < N; ++i) {
            const Point& p = points[i];
            if      (p.x >= 0.0 && p.y >= 0.0) local[0] += 1;
            else if (p.x <  0.0 && p.y >= 0.0) local[1] += 1;
            else if (p.x <  0.0 && p.y <  0.0) local[2] += 1;
            else                            local[3] += 1;
        }

        // Reduce thread‑local counts into the global bins
        #pragma omp atomic
        bins[0] += local[0];
        #pragma omp atomic
        bins[1] += local[1];
        #pragma omp atomic
        bins[2] += local[2];
        #pragma omp atomic
        bins[3] += local[3];
    }
}
