```cpp
#pragma once
#include <vector>
#include <cstdint>
#include <limits>

/* Return the length of the shortest path from source to dest in the undirected graph
   defined by the adjacency matrix A (row‑major).  A is an NxN matrix of 0/1 values.
   The graph is assumed to be connected and undirected.
*/
inline int shortestPathLength(const std::vector<int> &A, size_t N, int source, int dest)
{
    if (source == dest) return 0;

    /* Use a byte per node to avoid the special sparse representation of
       std::vector<bool>, which incurs bit‑packing overhead.  */
    std::vector<uint8_t> visited(N, 0);
    visited[source] = 1;

    /* Simple two‑vector queue implementation.  */
    std::vector<int> q;
    q.reserve(N);
    q.push_back(source);
    size_t head = 0;              // index of next element to pop
    std::vector<int> dist(N, -1);
    dist[source] = 0;

    while (head < q.size()) {
        int cur  = q[head++];
        int curd = dist[cur];

        /* Scan all neighbors of cur.  The inner loop is independent per
           candidate, so the compiler can vectorise or unroll it.  */
        const int *row = &A[cur * N];
        for (size_t j = 0; j < N; ++j) {
            if (row[j] && !visited[j]) {
                visited[j] = 1;
                dist[j] = curd + 1;
                if (j == (size_t)dest) return curd + 1;
                q.push_back((int)j);
            }
        }
    }

    return std::numeric_limits<int>::max();
}
