/* Count the number of doubles in the vector `x` that have a fractional part
   in [0, 0.25), [0.25, 0.5), [0.5, 0.75), and [0.75, 1). Store the counts in
   `bins`. Behaviour is identical to the reference implementation.  */
inline void countQuartiles(const std::vector<double> &x,
                           std::array<size_t, 4> &bins)
{
    // initialise output bins to zero
    bins[0] = bins[1] = bins[2] = bins[3] = 0;

    // Per‑thread local counters to avoid contention
    const int n_threads = omp_get_max_threads();
    std::vector<std::array<size_t,4>> local(n_threads);
    for (auto &arr : local) arr = {0,0,0,0};

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        auto &lc = local[tid];

        #pragma omp for nowait
        for (std::size_t i = 0; i < x.size(); ++i)
        {
            const double v   = x[i];
            const double frac = v - std::floor(v);   // fractional part [0,1)
            if      (frac < 0.25) ++lc[0];
            else if (frac < 0.5 ) ++lc[1];
            else if (frac < 0.75) ++lc[2];
            else                  ++lc[3];
        }
    }

    // merge per‑thread results
    for (int t = 0; t < n_threads; ++t)
    {
        const auto &lc = local[t];
        bins[0] += lc[0];
        bins[1] += lc[1];
        bins[2] += lc[2];
        bins[3] += lc[3];
    }
}
