   output: 2
*/
double closestPair(std::vector<double> const& x)
{
    const size_t n = x.size();
    if (n < 2) return 0.0;

    // Make a sorted copy of the input (sorted once, reused for all threads)
    std::vector<double> sorted(x);
    std::sort(sorted.begin(), sorted.end());

    double minDist = std::numeric_limits<double>::max();

    // Reduce the number of pairs to check:
    // After sorting, the closest pair must be adjacent in the sorted order.
    // Parallel reduce over the adjacent differences.
#pragma omp parallel for reduction(min:minDist) schedule(static)
    for (size_t i = 0; i + 1 < n; ++i)
    {
        const double d = sorted[i + 1] - sorted[i];
        if (d < minDist) minDist = d;
    }

    return minDist;
}
