/* Fast Union‑Find implementation */
class UnionFind {
    std::vector<int> parent, sz;
public:
    explicit UnionFind(int n) : parent(n), sz(n, 1) {
        for (int i = 0; i < n; ++i) parent[i] = i;
    }
    int find(int x) {
        while (parent[x] != x) {
            parent[x] = parent[parent[x]];
            x = parent[x];
        }
        return x;
    }
    void unite(int a, int b) {
        int pa = find(a);
        int pb = find(b);
        if (pa == pb) return;
        if (sz[pa] < sz[pb]) std::swap(pa, pb);
        parent[pb] = pa;
        sz[pa] += sz[pb];
    }
    int max_set_size() const {
        int m = 0;
        for (int i = 0; i < (int)parent.size(); ++i)
            if (parent[i] == i) m = std::max(m, sz[i]);
        return m;
    }
};

/* Return the number of vertices in the largest component of the graph defined by
   the adjacency matrix A (row‑major). */
int largestComponent(std::vector<int> const& A, size_t N) {
    UnionFind uf(N);

    /* Parallel union of all 1‑edges.  Only i < j to avoid duplicate work. */
    #pragma omp parallel for schedule(dynamic)
    for (size_t i = 0; i < N; ++i) {
        const int base = int(i * N);
        for (size_t j = i + 1; j < N; ++j) {
            if (A[base + j] == 1)
                uf.unite(int(i), int(j));
        }
    }
    return uf.max_set_size();
}
