/*
 * Count the number of pixels in image with each grayscale intensity.
 * The vector `image` is a grayscale image with values 0-255.
 * Store the results in `bins`.
 * Example:
 *
 * input:  image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
 * output: [0, 0, 2, 0, 1, ...]
 *
 * Parallel version: uses OpenMP to split work over 8 threads
 * while ensuring deterministic result exactly matching the
 * single‑threaded implementation.
 */
inline void pixelCounts(std::vector<int> const& image,
                        std::array<std::size_t, 256> &bins)
{
    /* Initialise all bins to zero */
    bins.fill(0);

    /* Allocate a private buffer for each thread */
    const int n_threads = 8;
    std::array<std::array<std::size_t, 256>, n_threads> local_bins;

    for (int t = 0; t < n_threads; ++t) {
        local_bins[t].fill(0);
    }

    /* Parallel loop: each iteration increments a local counter. */
    #pragma omp parallel num_threads(n_threads)
    {
        const int id = omp_get_thread_num();
        const std::size_t chunk = image.size() / n_threads;
        const std::size_t start = id * chunk;
        const std::size_t end   = (id == n_threads - 1) ?
                                  image.size() : start + chunk;

        for (std::size_t i = start; i < end; ++i) {
            const int v = image[i];
            /* The input guarantees 0 <= v <= 255 */
            ++local_bins[id][static_cast<std::uint8_t>(v)];
        }
    }

    /* Aggregate local bins into the final result */
    for (int t = 0; t < n_threads; ++t) {
        for (std::size_t value = 0; value < 256; ++value) {
            bins[value] += local_bins[t][value];
        }
    }
}
