inline constexpr double INV3 = 1.0 / 3.0;

// Compute one iteration of a 3‑point 1D Jacobi stencil on `input`.
// Stores the result in `output`.  The caller guarantees `output.size() == input.size()`.
void jacobi1D(std::vector<double> const& input, std::vector<double> &output) {
    const size_t n = input.size();
    if (n == 0) return;

    // Pointers for fast element access
    const double *in  = input.data();
    double       *out = output.data();

    // Handle first and last elements separately to avoid boundary checks in the loop
    out[0] = (in[0] + (n > 1 ? in[1] : 0.0)) * INV3;
    out[n-1] = ( (n > 1 ? in[n-2] : 0.0) + in[n-1]) * INV3;

#pragma omp parallel for schedule(static)
    for (std::size_t i = 1; i + 1 < n; ++i) {
        // Cache-friendly summation
        out[i] = (in[i-1] + in[i] + in[i+1]) * INV3;
    }
}
