#include <numeric>
#include <algorithm>
#include <omp.h>

/* Compute the prefix (inclusive) sum of the vector `x` into `output`.
   Example:
     input:  [1, 7, 4, 6, 6, 2]
     output: [1, 8,12,18,24,26]
   The function preserves the exact behaviour of the original
   implementation but runs much faster on a modern 8‑core machine
   thanks to a hand‑crafted parallel prefix sum. */
inline void prefixSum(const std::vector<int64_t>& x, std::vector<int64_t>& output)
{
    const std::size_t n = x.size();
    if (n == 0) {
        output.clear();
        return;
    }
    if (n <= 2048) {
        // small vectors: serial scan is faster than any parallel overhead
        std::inclusive_scan(x.begin(), x.end(), output.begin());
        return;
    }

    // Allocate temporary storage for per‑chunk partial sums
    const int  threads = omp_get_num_threads() > 0 ? omp_get_max_threads() : 1;
    const std::size_t chunk = (n + threads - 1) / threads;

    std::vector<std::vector<int64_t>> local_sums(threads);

#pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        const std::size_t start = tid * chunk;
        const std::size_t end   = std::min(start + chunk, n);

        if (start >= n) return;

        local_sums[tid].resize(end - start);
        std::inclusive_scan(x.begin() + start, x.begin() + end,
                            local_sums[tid].begin());

        // Compute the offset for this chunk: sum of all previous chunks
        int64_t offset = 0;
        for (int i = 0; i < tid; ++i) {
            if (!local_sums[i].empty())
                offset += local_sums[i].back();
        }
        // Add the offset to all elements in the chunk
        std::transform(local_sums[tid].begin(), local_sums[tid].end(),
                       local_sums[tid].begin(),
                       [offset](int64_t v){ return v + offset; });

        // Copy the chunk result into the final output
        std::copy(local_sums[tid].begin(), local_sums[tid].end(),
                  output.begin() + start);
    }
}
