#pragma once
#include <vector>
#include <unordered_map>
#include <algorithm>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* In-place Doolittle LU factorisation for a sparse N×N matrix stored
 * in COO format.  The result is written into the row-major arrays L
 * and U (size N×N each).  L has a unit diagonal, U contains the upper
 * part of the original matrix after elimination.  The algorithm
 * preserves the exact semantics of the reference implementation.
 */
inline void luFactorize(std::vector<COOElement> const& A,
                        std::vector<double>       & L,
                        std::vector<double>       & U,
                        size_t                    N)
{
    /* Build a fast row‑to‑column hash map for the non‑zeros of A. */
    std::vector<std::unordered_map<size_t, double>> rowMap(N);
    for (const auto& e : A) {
        rowMap[e.row][e.column] = e.value;
    }

    /* Initialise L and U to zero. */
    std::fill(L.begin(), L.end(), 0.0);
    std::fill(U.begin(), U.end(), 0.0);

    /* Doolittle factorisation with OpenMP (parallel outer loop). */
    #pragma omp parallel for schedule(dynamic)
    for (size_t i = 0; i < N; ++i) {
        /* --- Compute U[i][j] for j >= i --- */
        for (size_t j = i; j < N; ++j) {
            /* Start with the original entry or 0 if missing. */
            double val = rowMap[i].count(j) ? rowMap[i][j] : 0.0;

            /* Subtract L[i][k] * U[k][j] for k < i. */
            for (size_t k = 0; k < i; ++k) {
                val -= L[i * N + k] * U[k * N + j];
            }
            U[i * N + j] = val;
        }

        /* --- Compute L[i][j] for j < i --- */
        for (size_t j = 0; j < i; ++j) {
            /* Start with the original entry or 0 if missing. */
            double val = rowMap[i].count(j) ? rowMap[i][j] : 0.0;

            /* Subtract L[i][k] * U[k][j] for k < j. */
            for (size_t k = 0; k < j; ++k) {
                val -= L[i * N + k] * U[k * N + j];
            }
            /* Divide by diagonal of U. */
            val /= U[j * N + j];
            L[i * N + j] = val;
        }
        /* unit diagonal of L */
        L[i * N + i] = 1.0;
    }
}
