/*********************************************************************
 * Optimized smallestArea implementation
 * ----------------------------------------------------
 *  • Uses a single O(n³) algorithm exactly equivalent to the
 *    original implementation.
 *  • Parallelises the outer two loops via OpenMP collapse(2) and a
 *    double reduction on the minimum area.
 *  • Keeps all data types and calculations identical, thus no
 *    change in numerical results.
 *********************************************************************/

#pragma once
#include <vector>
#include <limits>
#include <cmath>
#include <omp.h>

struct Point {
    double x;
    double y;
};

/* calculate the absolute area of triangle ABC */
inline double triArea(const Point& A, const Point& B, const Point& C) noexcept {
    return 0.5 * std::fabs( A.x * (B.y - C.y) +
                            B.x * (C.y - A.y) +
                            C.x * (A.y - B.y) );
}

/* Return the area of the smallest triangle that can be formed by
 * any 3 points in the input vector.
 */
double smallestArea(std::vector<Point> const& points) {
    const size_t n = points.size();
    if (n < 3) return 0.0;

    double minArea = std::numeric_limits<double>::max();

    /* parallelise the two outer loops with a reduction on minArea */
    #pragma omp parallel for collapse(2) schedule(static) \
        reduction(min : minArea)
    for (size_t i = 0; i < n - 2; ++i) {
        for (size_t j = i + 1; j < n - 1; ++j) {
            for (size_t k = j + 1; k < n; ++k) {
                const double area = triArea(points[i], points[j], points[k]);
                if (area < minArea) minArea = area;
            }
        }
    }
    return minArea;
}
