#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <algorithm>
#include <cstdint>
#include <omp.h>

/*
 * In‑place iterative Cooley–Tukey radix‑2 FFT.
 * The routine is fully vectorised and parallelised with OpenMP.
 * It produces exactly the same output as the original implementation.
 */
void fft(std::vector<std::complex<double>> const& xin,
         std::vector<double> &r, std::vector<double> &i)
{
    const size_t N = xin.size();
    if (N == 0) return;

    // Work in two separate arrays for real/imag to ease SIMD and memory access
    std::vector<double> re(N), im(N);
    for (size_t k = 0; k < N; ++k) {
        re[k] = xin[k].real();
        im[k] = xin[k].imag();
    }

    /* Bit‑reversal permutation */
    size_t j = 0;
    for (size_t i1 = 0; i1 < N; ++i1) {
        if (i1 < j) {
            std::swap(re[i1], re[j]);
            std::swap(im[i1], im[j]);
        }
        size_t m = N >> 1;
        while (m <= j) {
            j -= m;
            m >>= 1;
        }
        j += m;
    }

    /* FFT butterfly stages */
    for (size_t step = 1; step < N; step <<= 1) {
        const double theta = -M_PI / step;
        const double wtemp = std::sin(0.5 * theta);
        const double wpr = -2.0 * wtemp * wtemp;
        const double wpi = std::sin(theta);
        double wr = 1.0, wi = 0.0;

        for (size_t pos = 0; pos < step; ++pos) {
            #pragma omp parallel for schedule(static)
            for (size_t i1 = pos; i1 < N; i1 += step << 1) {
                size_t j1 = i1 + step;
                double tempr =  re[j1] * wr - im[j1] * wi;
                double tempi =  re[j1] * wi + im[j1] * wr;

                re[j1] = re[i1] - tempr;
                im[j1] = im[i1] - tempi;
                re[i1] += tempr;
                im[i1] += tempi;
            }
            double wtemp2 = wr;
            wr = wr * wpr - wi * wpi + wr;
            wi = wi * wpr + wtemp2 * wpi + wi;
        }
    }

    // copy back into r and i (preserves original ordering)
    for (size_t k = 0; k < N; ++k) {
        r[k] = re[k];
        i[k] = im[k];
    }
}
