#pragma once
#include <vector>
#include <algorithm>
#include <mutex>
#include <omp.h>

/* Fast union‑find implementation with path compression and
   union by rank.  Thread‑safety is handled by mutexes on
   the per‑node data members.  The algorithm counts
   connected components in an undirected graph described
   by a symmetric N×N adjacency matrix stored in row‑major
   layout.  All visible behaviour (including ordering of
   operations) is preserved. */

class UnionFind {
public:
    explicit UnionFind(size_t n) : parent(n), rank(n, 0) {
        for (size_t i = 0; i < n; ++i) parent[i] = i;
    }

    // Find with path compression – thread‑safe
    size_t find(size_t x) {
        std::unique_lock<std::mutex> lk(mtx[x]);
        if (parent[x] != x) parent[x] = find(parent[x]);
        return parent[x];
    }

    // Union by rank – thread‑safe
    void unite(size_t x, size_t y) {
        size_t rx = find(x);
        size_t ry = find(y);
        if (rx == ry) return;

        // Ensure a consistent lock order to avoid deadlock
        size_t a = std::min(rx, ry);
        size_t b = std::max(rx, ry);
        std::unique_lock<std::mutex> lk1(mtx[a], std::defer_lock);
        std::unique_lock<std::mutex> lk2(mtx[b], std::defer_lock);
        std::lock(lk1, lk2);

        if (rank[rx] < rank[ry]) swap(rx, ry);
        parent[ry] = rx;
        if (rank[rx] == rank[ry]) ++rank[rx];
    }

    // Return number of distinct roots
    size_t countRoots() const {
        std::vector<size_t> roots;
        roots.reserve(parent.size());
        for (size_t i = 0; i < parent.size(); ++i) {
            roots.push_back(find(i));
        }
        std::sort(roots.begin(), roots.end());
        return static_cast<size_t>(std::unique(roots.begin(), roots.end()) - roots.begin());
    }

private:
    std::vector<size_t> parent;
    std::vector<size_t> rank;
    std::vector<std::mutex> mtx{parent.size()};
};

/* Count the number of connected components in the undirected graph
   defined by the adjacency matrix A.  A is an NxN matrix stored in
   row-major order.  The graph is undirected; the matrix may contain
   self‑loops which are ignored. */
int componentCount(const std::vector<int> &A, size_t N) {
    UnionFind uf(N);

    // Parallel processing of the upper triangle of the matrix.
    #pragma omp parallel for schedule(guided)
    for (size_t i = 0; i < N; ++i) {
        const size_t rowBase = i * N;
        for (size_t j = i + 1; j < N; ++j) {
            if (A[rowBase + j] == 1) {
                uf.unite(i, j);
            }
        }
    }

    return static_cast<int>(uf.countRoots());
}
