inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int> &imageOut,
                           std::size_t N) {
    // Edge kernel (constant)
    constexpr int k[3][3] = { {-1, -1, -1},
                              {-1,  8, -1},
                              {-1, -1, -1} };

    const int *in = imageIn.data();
    int *out = imageOut.data();
    const std::size_t stride = N;

    // Parallelise outer loops with OpenMP, collapse to a single loop.
#pragma omp parallel for collapse(2) schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        for (std::size_t j = 0; j < N; ++j) {
            int sum = 0;
            /* Unroll the 3x3 neighbourhood manually for a small
               inner loop with fewer branches. */
            for (int di = -1; di <= 1; ++di) {
                std::size_t ni = i + di;
                if (ni >= N) continue;
                for (int dj = -1; dj <= 1; ++dj) {
                    std::size_t nj = j + dj;
                    if (nj >= N) continue;
                    sum += in[ni * stride + nj] * k[di + 1][dj + 1];
                }
            }
            out[i * stride + j] = std::min(255, std::max(sum, 0));
        }
    }
