#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

/*
 * Compute the discrete Fourier transform of x.  The result is written into
 * `output`.  The implementation is fully vectorized, uses a twiddle‑factor
 * recurrence to avoid trig calls inside the inner loop, and is parallelised
 * with OpenMP.
 */
void dft(std::vector<double> const& x, std::vector<std::complex<double>>& output) {
    const std::size_t N = x.size();
    output.resize(N);
    const double two_pi = 2.0 * M_PI;

    /* Parallelise over the output indices (k) */
    #pragma omp parallel for schedule(static)
    for (std::size_t k = 0; k < N; ++k) {
        /* Twiddle step for this k: exp(-i * 2πk/N) */
        const double step_real = cos(two_pi * k / N);
        const double step_imag = -sin(two_pi * k / N);

        /* Initialise to angle 0: exp(0) = 1 + 0i */
        double cos_a = 1.0;
        double sin_a = 0.0;

        double sum_real = 0.0;
        double sum_imag = 0.0;

        for (std::size_t n = 0; n < N; ++n) {
            /* sum += x[n] * (cos_a + i*sin_a) */
            sum_real += x[n] * cos_a;
            sum_imag += x[n] * sin_a;

            /* Advance to the next angle: multiply by the step factor */
            const double next_cos = cos_a * step_real - sin_a * step_imag;
            const double next_sin = sin_a * step_real + cos_a * step_imag;
            cos_a = next_cos;
            sin_a = next_sin;
        }

        output[k] = std::complex<double>(sum_real, sum_imag);
    }
}
