    const double * restrict xv = x.data();
    double * restrict yv = y.data();

    const size_t block_size = 64;                 // cache-friendly block size (adjustable)
    const size_t num_blocks = (N + block_size - 1) / block_size;

    #pragma omp parallel for schedule(static, 16)
    for (size_t i = 0; i < M; ++i) {
