        const double *row = a + i * N;

        for (size_t b = 0; b < num_blocks; ++b) {
            const size_t start = b * block_size;
            const size_t end   = std::min(start + block_size, N);
#pragma GCC ivdep
            for (size_t j = start; j != end; ++j) {
                sum += row[j] * xv[j];
            }
        }
        yv[i] = sum;
    }
