#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <cstddef>
#include <omp.h>

struct COOElement {
   size_t row, column;
   double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:

   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
inline double absd(double v) { return v < 0 ? -v : v; }

void solveLinearSystem(std::vector<COOElement> const& A,
                       std::vector<double> const& b,
                       std::vector<double> &x,
                       size_t N)
{
   // Allocate a flat dense matrix (row-major)
   std::vector<double> mat(N * N, 0.0);
   // Fill matrix from COO – parallelizable
   #pragma omp parallel for schedule(static)
   for (size_t idx = 0; idx < A.size(); ++idx) {
      const auto &e = A[idx];
      mat[e.row * N + e.column] = e.value;
   }

   // Working copy of b
   std::vector<double> b_copy = b;
   x.assign(N, 0.0);

   // Gaussian elimination with partial pivoting
   for (size_t i = 0; i < N; ++i) {
      // ---- Find pivot row ----
      size_t maxRow = i;
      double maxVal = absd(mat[i * N + i]);

      #pragma omp parallel for reduction(max:maxVal) schedule(static)
      for (size_t k = i + 1; k < N; ++k) {
         double val = absd(mat[k * N + i]);
         if (val > maxVal) {
            maxVal = val;
            #pragma omp critical
            maxRow = k;
         }
      }

      // Swap rows if needed
      if (maxRow != i) {
         for (size_t j = i; j < N; ++j) {
            std::swap(mat[maxRow * N + j], mat[i * N + j]);
         }
         std::swap(b_copy[maxRow], b_copy[i]);
      }

      double pivot = mat[i * N + i];

      // ---- Eliminate rows below i ----
      #pragma omp parallel for schedule(static)
      for (size_t k = i + 1; k < N; ++k) {
         double factor = -mat[k * N + i] / pivot;
         // First element becomes zero
         mat[k * N + i] = 0.0;
         for (size_t j = i + 1; j < N; ++j) {
            mat[k * N + j] += factor * mat[i * N + j];
         }
         b_copy[k] += factor * b_copy[i];
      }
   }

   // Back substitution
   for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
      double sum = 0.0;
      for (size_t j = i + 1; j < N; ++j) {
         sum += mat[i * N + j] * x[j];
      }
      x[i] = (b_copy[i] - sum) / mat[i * N + i];
   }
}
