inline void sortIgnoreZero(std::vector<int> &x)
{
    const size_t n = x.size();
    // Parallel extraction of non‑zero elements
    std::vector<std::vector<int>> local(n / 8 + 1);   // one per thread
    #pragma omp parallel
    {
        const unsigned tid = omp_get_thread_num();
        const unsigned nthreads = omp_get_num_threads();
        const size_t chunk = (n + nthreads - 1) / nthreads; // ceil
        const size_t start = tid * chunk;
        const size_t end   = std::min(start + chunk, n);

        std::vector<int> &lv = local[tid];
        for (size_t i = start; i < end; ++i)
            if (x[i] != 0)
                lv.push_back(x[i]);

        // preallocate to avoid repeated reallocations
        lv.reserve(lv.size() * 2 + 10);
    }

    // Concatenate and sort
    std::vector<int> nonZero;
    nonZero.reserve(n);
    for (auto &lv : local) nonZero.insert(nonZero.end(), lv.begin(), lv.end());
    std::sort(nonZero.begin(), nonZero.end());

    // Write sorted values back preserving zero positions
    size_t idx = 0;
    for (size_t i = 0; i < n; ++i)
        if (x[i] != 0)
            x[i] = nonZero[idx++];
}
