    // Parallel reduction over the vector
    detail::MinInfo best = init_min_info(x[0], 0);
    #pragma omp parallel for reduction(+:best)
    for (int i = 1; i < static_cast<int>(x.size()); ++i) {
        auto cur = init_min_info(x[i], static_cast<size_t>(i));
        best = cur + best;            // operator+ prefers smaller diff
    }
    return best.index;
