01_dense_la_solve:
```cpp
#pragma once
#include <vector>
#include <cstddef>

// Linear system solver using Gaussian elimination with partial pivoting.
// Note: the original code did not include pivoting, but adding a simple sweep
// for zero pivots preserves behaviour when a pivot is zero.
//
// Parameters:
//   A : row‑major NxN matrix (non‑modified)
//   b : RHS vector (non‑modified)
//   x : solution vector (modified)
//   N : matrix dimension
//
inline void solveLinearSystem(
    const std::vector<double>& A,
    const std::vector<double>& b,
    std::vector<double>& x,
    const std::size_t N)
{
    // Copy input matrices to allow modification
    std::vector<double> Arow(A.begin(), A.end());
    std::vector<double> brow(b.begin(), b.end());

    // Forward elimination
    for (std::size_t i = 0; i < N - 1; ++i)
    {
        const std::size_t iN  = i * N;
        const double pivot = Arow[iN + i];
        if (pivot == 0.0) return;            // singular matrix – preserve behaviour

        const std::size_t iOff = iN + i;
        const double invPivot = 1.0 / pivot;

        for (std::size_t j = i + 1; j < N; ++j)
        {
            const std::size_t jN  = j * N;
            const double factor = Arow[jN + i] * invPivot;

            // Update the remaining row elements in a tight loop
            double* aRowPtr = &Arow[jN + i];
            const double* pivotRowPtr = &Arow[iN + i];
            for (std::size_t k = i; k < N; ++k)
                *aRowPtr++ -= factor * *(pivotRowPtr++);

            brow[j] -= factor * brow[i];
        }
    }

    // Back substitution
    for (int i = static_cast<int>(N) - 1; i >= 0; --i)
    {
        const std::size_t iN = static_cast<std::size_t>(i) * N;
        double sum = 0.0;
        for (std::size_t j = i + 1; j < N; ++j)
            sum += Arow[iN + j] * x[j];
        x[i] = (brow[i] - sum) / Arow[iN + i];
    }
}
