```cpp
#pragma once
#include <vector>
#include <omp.h>

/*
 * Factorize the matrix A into A=LU where L is a lower triangular matrix
 * and U is an upper triangular matrix.  The results for L and U are
 * stored in the original matrix A.
 *
 * A is an NxN matrix stored in row-major order.
 *
 * Example:
 *   input: [[4, 3], [6, 3]]
 *   output: [[4, 3], [1.5, -1.5]]
 */
inline void luFactorize(std::vector<double> &A, size_t N) {
    // Parallel over the outer loop in blocks of rows that use the same pivot row.
    for (size_t k = 0; k < N; ++k) {
        const size_t kRow = k * N;
        const double pivot = A[kRow + k];          // A[k][k]
        if (pivot == 0.0) continue;                // Singular.  Keep behaviour.

        // All rows i > k compute their multiplier and update their remaining
        // columns.  These rows are independent and can be processed in parallel.
        #pragma omp parallel for schedule(static, 64) \
            private(k) firstprivate(pivot) shared(A, N, kRow)
        for (size_t i = k + 1; i < N; ++i) {
            const size_t iRow = i * N;
            const double factor = A[iRow + k] / pivot;   // L[i][k]
            A[iRow + k] = factor;                       // store L[i][k]

            // Update the rest of the row.  The inner loop operates on a
            // contiguous memory region, which gives the compiler plenty
            // of room for vectorisation.
            double *aRow  = &A[iRow + k + 1];
            const double *kRowPtr = &A[kRow + k + 1];
            size_t remaining = N - k - 1;
            for (size_t j = 0; j < remaining; ++j) {
                aRow[j] -= factor * kRowPtr[j];
            }
        }
    }
}
