/* Compute z = alpha*x + y where x and y are sparse vectors.
 * The result is stored in z. The function is thread‑safe and
 * preserves the behaviour of the original scalar implementation.
 */
void sparseAxpy(double alpha,
                const std::vector<Element>& x,
                const std::vector<Element>& y,
                std::vector<double>& z)
{
    /* Parallel addition of y.  Each thread performs an atomic add
     * for its chunk of elements.  This guarantees correct results
     * even when x and y share indices.                         */
