    for (size_t i = 0; i < y.size(); ++i) {
        const size_t idx = y[i].index;
        const double val = y[i].value;
#pragma omp atomic
        z[idx] += val;
    }

    /* Parallel addition of alpha * x.  Again each thread uses
     * an atomic add to avoid race conditions on overlapping
     * indices.                                                */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < x.size(); ++i) {
        const size_t idx = x[i].index;
        const double val = alpha * x[i].value;
#pragma omp atomic
        z[idx] += val;
    }
}
