#include <numeric>

/*
 * Computes the rank index of each element in `x` and stores it in `ranks_`.
 * The rank of an element is its position in the ascendingly sorted order of `x`.
 *
 * Example:
 *   x = [3.1, 2.8, 9.1, 0.4, 3.14]
 *   ranks_ = [2, 1, 4, 0, 3]
 */
void ranks(std::vector<float> const& x, std::vector<size_t> &ranks_) {
    // ───── Step 1: Create an array of (value, original_index) pairs ─────
    struct Elem { float value; size_t idx; };
    std::vector<Elem> elems;
    elems.reserve(x.size());
    for (size_t i = 0; i < x.size(); ++i)
        elems.push_back({x[i], i});

    // ───── Step 2: Sort the array by value ─────
    std::sort(elems.begin(), elems.end(),
              [](const Elem &a, const Elem &b) { return a.value < b.value; });

    // ───── Step 3: Write the rank for each original element ─────
    ranks_.resize(x.size());
    for (size_t rank = 0; rank < elems.size(); ++rank)
        ranks_[elems[rank].idx] = rank;
}
