#include <algorithm>
#include <numeric>
#include <omp.h>
#include <cmath>

struct Point {
    double x, y;
};

static inline double sq(double v) { return v * v; }
static inline double dist(const Point& a, const Point& b) {
    return std::sqrt(sq(b.x - a.x) + sq(b.y - a.y));
}

/* ------------- helper structs ------------- */
struct TmpPoint {
    double x, y;
};

/* ------------- core algorithm ------------- */
static double closest_pair_rec(std::vector<Point>& pts, std::vector<Point>& aux, size_t l, size_t r) {
    if (r - l <= 3) {                       // brute‑force for few points
        double d = std::numeric_limits<double>::max();
        for (size_t i = l; i < r; ++i)
            for (size_t j = i + 1; j < r; ++j)
                d = std::min(d, dist(pts[i], pts[j]));
        std::sort(pts.begin() + l, pts.begin() + r, [](const Point& a, const Point& b){ return a.y < b.y; });
        return d;
    }

    size_t m = (l + r) / 2;
    double midx = pts[m].x;

    double dl = closest_pair_rec(pts, aux, l, m);
    double dr = closest_pair_rec(pts, aux, m, r);
    double d = std::min(dl, dr);

    /* merge step: produce aux sorted by y */
    std::merge(pts.begin() + l, pts.begin() + m,
               pts.begin() + m, pts.begin() + r,
               aux.begin(), [](const Point& a, const Point& b){ return a.y < b.y; });

    /* copy back */
    std::copy(aux.begin(), aux.begin() + (r - l), pts.begin() + l);

    /* build strip */
    std::vector<Point> strip;
    strip.reserve(r - l);
    for (size_t i = l; i < r; ++i)
        if (std::abs(pts[i].x - midx) < d)
            strip.push_back(pts[i]);

    /* check strip */
    for (size_t i = 0; i < strip.size(); ++i) {
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < d; ++j) {
            d = std::min(d, dist(strip[i], strip[j]));
        }
    }

    return d;
}

/* ------------- interface ------------- */
double closestPair(std::vector<Point> const& points) {
    if (points.size() < 2) return 0.0;

    std::vector<Point> pts = points;
    std::sort(pts.begin(), pts.end(), [](const Point& a, const Point& b){ return a.x < b.x; });

    /* auxiliary buffer */
    std::vector<Point> aux(pts.size());

    /* parallel launch: divide into 4 chunks, each processes half recursively */
    #pragma omp parallel
    {
        #pragma omp single
        {
            /* nested parallelism is disabled (max 8 threads) */
            #pragma omp task firstprivate(pts, aux) shared(d_)
            {
                d_ = closest_pair_rec(pts, aux, 0, pts.size());
            }
        }
    }

    /* the result is in d_ */
    double d = d_;
    return d;
}
