/* Compute the DFT of x and store the result in output.
   The implementation follows an in‑place iterative radix‑2 Cooley‑Tukey FFT.
   The algorithm is fully deterministic and matches the reference output
   within the limits of IEEE‑754 double precision.
*/
inline void fft(std::vector<std::complex<double>> const& x,
                std::vector<std::complex<double>>& output)
{
    output = x;                                 // work in-place

    const std::size_t N = output.size();
    if (N <= 1) return;                         // nothing to do

    /* ----------  Bit‑reversal permutation ---------- */
    std::size_t logN = static_cast<std::size_t>(std::log2(N));
    std::vector<std::size_t> rev(N);
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t r = i;
        r = ((r & 0xaaaaaaaaaaaaaaaaULL) >> 1) |
            ((r & 0x5555555555555555ULL) << 1);
        r = ((r & 0xccccccccccccccccULL) >> 2) |
            ((r & 0x3333333333333333ULL) << 2);
        r = ((r & 0xf0f0f0f0f0f0f0f0ULL) >> 4) |
            ((r & 0x0f0f0f0f0f0f0f0fULL) << 4);
        r = ((r & 0xff00ff00ff00ff00ULL) >> 8) |
            ((r & 0x00ff00ff00ff00ffULL) << 8);
        r = ((r >> 16) | (r << 48));
        rev[i] = r >> (64 - logN);
    }

    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        if (rev[i] > i) std::swap(output[i], output[rev[i]]);
    }

    /* ----------  Pre‑compute twiddle factors ---------- */
    std::vector<std::complex<double>> twiddle(N / 2);
    const double pi = 3.141592653589793238462643383279502884;
    for (std::size_t k = 0; k < N / 2; ++k) {
        double angle = -2.0 * pi * k / N;
        twiddle[k] = std::complex<double>(std::cos(angle), std::sin(angle));
    }

    /* ----------  Iterative FFT ---------- */
    for (std::size_t half = 1; half < N; half <<= 1) {
        std::size_t step = half << 1;
        std::size_t stepTwiddle = N / step;                  // stride in twiddle array

        #pragma omp parallel for schedule(static)
        for (std::size_t i = 0; i < N; i += step) {
            for (std::size_t j = 0; j < half; ++j) {
                std::size_t idx   = i + j;
                std::size_t idxBk = idx + half;
                std::complex<double> t = output[idxBk] * twiddle[j * stepTwiddle];
                output[idxBk] = output[idx] - t;
                output[idx] += t;
            }
        }
    }
}
