/* Return the index of the first even number in the vector x.
   Examples:
   input: [7, 3, 9, 5, 5, 7, 2, 9, 12, 11]
   output: 6
   input: [3, 8, 9, 9, 3, 4, 8, 6]
   output: 1
*/
inline size_t findFirstEven(std::vector<int> const& x) {
    size_t sz = x.size();
    // `ans` starts with a value larger than any valid index.
    size_t ans = sz + 1;

    #pragma omp parallel for schedule(static) reduction(min:ans)
    for (ptrdiff_t i = 0; i < static_cast<ptrdiff_t>(sz); ++i) {
        // Test evenness with a bit‑wise check: faster than `% 2`.
        if ((x[static_cast<size_t>(i)] & 1) == 0) {
            // Convert ptrdiff_t to size_t for comparison.
            ans = (static_cast<size_t>(i) < ans) ? static_cast<size_t>(i) : ans;
        }
    }

    return (ans == sz + 1) ? sz : ans;
}
