// bit–reversal shuffle (in‑place, O(N) with no branching inside the loop)
static void bit_reverse(std::vector<std::complex<double>>& x) {
    unsigned int n = x.size();
    unsigned int m = 0;
    for (unsigned int temp=n; temp>1; temp>>=1) m++;
    unsigned int j=0;
    for (unsigned int i=0;i<n;i++) {
        if (i<j) std::swap(x[i],x[j]);
        unsigned int mask = n>>1;
        while (j & mask) {
            j ^= mask;
            mask >>= 1;
        }
        j |= mask;
    }
}

// parallel radix‑2 FFT (in‑place)
static void fft_helper(std::vector<std::complex<double>>& x) {
    unsigned int n = x.size();
    if (n <= 1) return;

    // 1. bit‑reverse input to bring butterflies in order
    bit_reverse(x);

    std::vector<std::complex<double>> w;
    precompute_twiddles(w, n);

    // 2. iterative stages
    for (unsigned int len=2, half=1; len<=n; len<<=1, half<<=1) {
        double step = static_cast<double>(n) / len;
        #pragma omp parallel for schedule(static)
        for (unsigned int i=0; i<n; i+=len) {
            for (unsigned int j=0; j<half; ++j) {
                std::size_t idx = i + j;
                std::size_t l = idx + half;
                std::complex<double> t = w[j * step] * x[l];
                x[l] = x[idx] - t;
                x[idx] += t;
            }
        }
    }
}

/* Compute the inverse fourier transform of x in-place.
   Exact behavior preserved with respect to the original code. */
inline void ifft(std::vector<std::complex<double>>& x) {
    // conjugate
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    // forward FFT
    fft_helper(x);

    // conjugate again
    std::transform(x.begin(), x.end(), x.begin(),
                   [](const std::complex<double>& v){ return std::conj(v); });

    // scale by 1/N
    double invN = 1.0 / static_cast<double>(x.size());
    #pragma omp parallel for schedule(static)
    for (std::size_t i=0; i<x.size(); ++i)
        x[i] *= invN;
}
