    for (int i = 0; i < static_cast<int>(N); ++i) {
        const int rowBase = i * stride;
        for (int j = 0; j < static_cast<int>(N); ++j) {
            // Use 16‑bit integer to hold the sum (max 8)
            uint16_t sum = 0;
