            if (i < static_cast<int>(N)-1) {
                if (j > 0)     sum += input[idx + stride - 1];
                sum +=          input[idx + stride];
                if (j < static_cast<int>(N)-1) sum += input[idx + stride + 1];
            }
            if (j > 0)         sum += input[idx - 1];
            if (j < static_cast<int>(N)-1) sum += input[idx + 1];

            // Game‑of‑Life rules via a small state machine
            uint8_t cur = static_cast<uint8_t>(input[idx] & 1);
            uint8_t res;
            if (cur) {               // live
                res = (sum == 2 || sum == 3) ? 1 : 0;
            } else {                 // dead
                res = (sum == 3) ? 1 : 0;
            }
