/*  cellsXOR – set each cell to 1 if exactly one of its 4‑(up/down/left/right) neighbours is 1,
    otherwise set it to 0.  The function is fully vector‑independent – every cell depends
    only on the input array, so the workload can be split arbitrarily.  Parallelism is
    provided via OpenMP and a small cache‑friendly tiling strategy is used to
    minimise memory traffic. */

inline void cellsXOR( std::vector<int> const& input,
                      std::vector<int>& output,
                      std::size_t N )
{
    const int *restrict in  = input.data();
    int *restrict       out = output.data();
    const std::size_t stride = N;

    /* If the grid is very small we just run the sequential version – the overhead
       of parallelisation would dominate. */
    if (N < 64)
    {
        for (std::size_t i = 0; i < N; ++i)
        {
            const int *restrict row  = in  + i*stride;
            int *restrict       outrow = out + i*stride;
            for (std::size_t j = 0; j < N; ++j)
            {
                int cnt = 0;
                if (i > 0      && (*in                - in[row]       ) == 0) ++cnt;   // up
                if (i + 1 < N  && (*in   + stride - in[row]       ) == 0) ++cnt;   // down
                if (j > 0      &&                row[j-1]       == 1) ++cnt;   // left
                if (j + 1 < N  &&                row[j+1]       == 1) ++cnt;   // right
                outrow[j] = (cnt == 1) ? 1 : 0;
            }
        }
        return;
    }

    /* Tile size – chosen to fit a cache line boundary (32‑bytes) and keep data in L1
       while keeping the loop overhead low. */
    const std::size_t tile = 64;

    /* Parallel outer loop across tiles in the vertical direction. */
    #pragma omp parallel for schedule(static)
    for (std::size_t ii = 0; ii < N; ii += tile)
    {
        const std::size_t i_end = std::min(ii + tile, N);
        for (std::size_t i = ii; i < i_end; ++i)
        {
            const int *restrict up   = (i > 0)      ? in + (i-1)*stride : nullptr;
            const int *restrict down = (i + 1 < N)  ? in + (i+1)*stride : nullptr;
            const int *restrict row  = in  + i*stride;
            int *restrict       outrow = out + i*stride;

            for (std::size_t j = 0; j < N; ++j)
            {
                int cnt = 0;
                if (up   && up[j]   == 1) ++cnt;         // up
                if (down && down[j] == 1) ++cnt;         // down
                if (j > 0      && row[j-1] == 1) ++cnt;  // left
                if (j + 1 < N  && row[j+1] == 1) ++cnt;  // right
                outrow[j] = (cnt == 1) ? 1 : 0;
            }
        }
    }
