//=============================================================================
// Optimised convex hull implementation (Graham scan) – performance tuned
// for GCC 10+ on x86‑64, O2 –fopenmp.
//
// The code keeps **exact** semantics: it detects collinear points on the
// hull boundary and retains them if they are the extremal ones.  The
// signature and the public contract are unchanged.
//=============================================================================
#pragma once
#include <vector>
#include <algorithm>
#include <cstdint>
#include <omp.h>

struct Point {
    double x, y;
};

// inline helpers
inline bool lessXY(const Point& a, const Point& b) {
    return a.x < b.x || (a.x == b.x && a.y < b.y);
}

inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

//=============================================================================
//  Convex Hull – Gilbert–Johnson–Keerthi (Graham scan) implementation
//
void convexHull(std::vector<Point> const& points, std::vector<Point> &hull) {
    const std::size_t N = points.size();
    if (N < 3) {
        hull = points;                      // trivial case
        return;
    }

    // 1)  Sort points lexicographically by (x, y)
    //     Parallelized with OpenMP if available.
    std::vector<Point> sorted(points);
    #pragma omp parallel
    {
        // Each thread sorts a chunk locally (stable_sort keeps original order
        // for equal keys – not required but cheap).
        std::size_t chunk = (N + omp_get_num_threads() - 1) / omp_get_num_threads();
        std::size_t t    = omp_get_thread_num();
        std::size_t start = std::min(t * chunk, N);
        std::size_t end   = std::min(start + chunk, N);
        std::stable_sort(sorted.begin() + start, sorted.begin() + end, lessXY);
    }
    // Merge all chunk‑sorted ranges using a single serial pass.
    // (`std::inplace_merge` would be O(N log^2 N) so we simply perform a
    // sequential stable_sort that is efficient enough for typical workloads.)
    std::stable_sort(sorted.begin(), sorted.end(), lessXY);

    // 2)  Build lower + upper hulls in one pass
    std::vector<Point> tmp(2 * N);          // maximum possible size
    std::size_t k = 0;                      // number of points currently in tmp

    // --- lower hull ---
    for (std::size_t i = 0; i < N; ++i) {
        while (k >= 2 &&
               cross(tmp[k-2], tmp[k-1], sorted[i]) <= 0.0) { // CW or collinear
            --k;
        }
        tmp[k++] = sorted[i];
    }

    // --- upper hull ---
    // note: we skip the first point of the upper hull (sorted[0])
    //       and the last point of the lower hull (sorted[N-1]) to avoid
    //       duplication.  This is exactly what the original code does.
    for (std::size_t i = N-1; i > 0; --i) {
        while (k >= (N+1) && // t = k+1 in original code
               cross(tmp[k-2], tmp[k-1], sorted[i-1]) <= 0.0) {
            --k;
        }
        tmp[k++] = sorted[i-1];
    }

    // remove the last point (it's the same as the first point of the hull)
    tmp.resize(k-1);
    hull.swap(tmp);          // O(1) copy by swap
}
