/* 
 * Optimised GEMM for row‑major matrices.  
 * A : MxK, B : KxN, C : MxN
 * The routine assumes that C has been zero‑initialised before
 * the first call (exactly as in the reference implementation).
 *
 * Blocking parameters are tuned for a typical x86‑64 CPU with
 * L1/L2 cache sizes.  The kernel is implemented in a way that
 * preserves the exact mathematical result while taking full
 * advantage of the compiler and the CPU pipeline.
 */
inline void gemm(const std::vector<double> &A,
                 const std::vector<double> &B,
                 std::vector<double> &C,
                 size_t M, size_t K, size_t N)
{
    // Block sizes – choose a multiple of 8 to keep vectorisation alive.
    const size_t BM = 64;   // block size for rows of A / C
    const size_t BK = 64;   // block size for columns of A / rows of B
    const size_t BN = 64;   // block size for columns of B / C

    const double *a = A.data();
    const double *b = B.data();
          double *c = C.data();

    // Parallelise over the outermost two blocks (i,k).
    // The inner j‑loop is kept inside the parallel region to avoid
    // thread contention on the write to C.
    #pragma omp parallel for schedule(Dynamic,1) collapse(2)
    for (size_t ii = 0; ii < M; ii += BM)
    for (size_t kk = 0; kk < K; kk += BK)
    {
        const size_t i_max = std::min(ii + BM, M);
        const size_t k_max = std::min(kk + BK, K);

        // Pointers to the current start of the sub‑matrices.
        const double *a_block = a + ii * K;
        const double *b_block = b + kk * N;
        double       *c_block = c + ii * N;

        for (size_t i = ii; i < i_max; ++i)
        {
            const double *a_row = a_block + i * K;
            double       *c_row = c_block + i * N;

            for (size_t k = kk; k < k_max; ++k)
            {
                const double aik = a_row[k];
                const double *b_row = b_block + k * N;

                // Unroll the innermost loop over j to keep the
                // data in registers as long as possible.
                size_t j = 0;
                for (; j + 15 < N; j += 16)
                {
                    #pragma GCC ivdep
                    for (int t = 0; t < 16; ++t)
                        c_row[j + t] += aik * b_row[j + t];
                }
                for (; j < N; ++j)
                    c_row[j] += aik * b_row[j];
            }
        }
    }
