#include <complex>
#include <cmath>
#include <algorithm>
#include <omp.h>

inline void fftConjugate(std::vector<std::complex<double>>& x)
{
    const uint32_t N = static_cast<uint32_t>(x.size());
    if (N == 0) return;

    // 1. Compute bit‑reversal permutation
    const uint32_t logN = static_cast<uint32_t>(std::log2(N));
    std::vector<uint32_t> rev(N);
    for (uint32_t i = 0; i < N; ++i) {
        uint32_t n = i;
        n = ((n & 0xAAAAAAAAu) >> 1) | ((n & 0x55555555u) << 1);
        n = ((n & 0xCCCCCCCCu) >> 2) | ((n & 0x33333333u) << 2);
        n = ((n & 0xF0F0F0F0u) >> 4) | ((n & 0x0F0F0F0Fu) << 4);
        n = ((n & 0xFF00FF00u) >> 8) | ((n & 0x00FF00FFu) << 8);
        n = (n >> 16) | (n << 16);
        rev[i] = n >> (32 - logN);
    }

    // 2. Reorder data according to the bit‑reversal table
    std::vector<std::complex<double>> buf(N);
    for (uint32_t i = 0; i < N; ++i)
        buf[i] = x[rev[i]];

    // 3. Iterative in‑place Cooley‑Tukey (decimation‑in‑time)
    for (uint32_t s = 1; s <= logN; ++s)
    {
        const uint32_t m   = 1u << s;          // stage length
        const uint32_t half = m >> 1;          // half stage length
        const double  theta = -M_PI / half;    // angle for this stage
        const std::complex<double> wlen = std::polar(1.0, theta);

        #pragma omp parallel for schedule(static)
        for (uint32_t i = 0; i < N; i += m)
        {
            std::complex<double> w(1.0, 0.0);
            for (uint32_t j = 0; j < half; ++j)
            {
                const std::complex<double> u = buf[i + j];
                const std::complex<double> v = buf[i + j + half] * w;
                buf[i + j]         = u + v;
                buf[i + j + half]  = u - v;
                w *= wlen;
            }
        }
    }

    // 4. Copy back to the original vector
    std::copy(buf.begin(), buf.end(), x.begin());

    // 5. Conjugate the result
    #pragma omp parallel for schedule(static)
    for (int64_t i = 0; i < static_cast<int64_t>(N); ++i)
        x[static_cast<size_t>(i)] = std::conj(x[static_cast<size_t>(i)]);
}
