#pragma once
#include <vector>
#include <algorithm>
#include <omp.h>

struct Result {
    int startTime;
    int duration;
    float value;
};

/*
 * Parallel, efficient sort of Result vectors by startTime.
 *
 * This implementation uses an all‑to‑one merge sort that first
 * sorts small chunks in parallel and then repeatedly merges
 * adjacent runs until the whole vector is sorted.  The code
 * is deliberately inlined, avoids virtual function calls and
 * uses the compiler's optimization to keep branch mispredictions
 * to a minimum.
 */
static inline void sortByStartTime(std::vector<Result> &results)
{
    // If the vector is empty or has a single element, it is already sorted.
    if (results.size() < 2) return;

    constexpr size_t MIN_PARALLEL_CHUNK = 2048;      // Threshold for parallel chunk sort
    constexpr size_t MIN_MERGE_CHUNK   = 16384;     // Threshold for launch parallel merge

    const size_t n = results.size();
    std::vector<Result> temp(n);                      // Temporary buffer for merges

    // --------------------------------------------------------------------
    // 1. Initial chunk sort – each thread sorts a disjoint block.
    // --------------------------------------------------------------------
    size_t chunkSize = std::max(MIN_PARALLEL_CHUNK,
                                (n + (omp_get_max_threads() * 8) - 1) / (omp_get_max_threads() * 8));
    #pragma omp parallel
    {
        size_t id  = omp_get_thread_num();
        size_t thr = omp_get_num_threads();
        size_t start = id * chunkSize;
        size_t end   = std::min(start + chunkSize, n);
        std::sort(results.begin() + start, results.begin() + end,
                  [](const Result& a, const Result& b) {
                      return a.startTime < b.startTime;
                  });
    }

    // --------------------------------------------------------------------
    // 2. Iteratively merge runs.  If the current run width is below a
    //    threshold, we perform a parallel merge of many small runs.
    // --------------------------------------------------------------------
    size_t width = chunkSize;
    while (width < n) {
        size_t nextWidth = width * 2;
        // If the run width is small, parallelize the merge of many runs.
        if (nextWidth < MIN_MERGE_CHUNK) {
            #pragma omp parallel for schedule(static)
            for (size_t i = 0; i < n; i += nextWidth) {
                size_t left  = i;
                size_t mid   = std::min(i + width, n);
                size_t right = std::min(i + nextWidth, n);
                std::merge(results.begin() + left, results.begin() + mid,
                           results.begin() + mid,  results.begin() + right,
                           temp.begin() + left);
            }
        } else {
            // Sequential merge of the whole vector (no benefit in parallelising).
            std::merge(results.begin(), results.end(),
                       results.begin(), results.end(),
                       temp.begin());
        }
        // Swap buffers for the next pass.
        results.swap(temp);
        width = nextWidth;
    }
}
