#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/*
 * Optimised 5‑point Jacobi stencil.
 * The implementation uses:
 *   • OpenMP parallelisation (collapse of the outer loops)
 *   • Pointer arithmetic to reduce index calculation overhead
 *   • Explicit boundary handling so the inner loop is fully vectorisable
 *   • Loop unrolling of 4 elements in the inner dimension
 *   • Minimal branch prediction penalties
 *
 * The function preserves the exact behaviour of the reference implementation
 * – zero is used for out‑of‑bounds accesses.
 */
void jacobi2D(std::vector<double> const& input,
              std::vector<double> &output,
              size_t N)
{
    const double *in  = input.data();
    double       *out = output.data();

    /* Pre‑compute strides for easier pointer arithmetic */
    const size_t stride = N;
    const size_t stride2 = 2 * stride;          // (i+2)*N
    const size_t strideMinus2 = (size_t)-2 * stride; // (i-2)*N (used via subtraction)

    /* Handle the trivial cases where N<3 – the general case below
       assumes at least one interior element per dimension. */
    if (N <= 2) {
        #pragma omp parallel for collapse(2)
        for (size_t i = 0; i < N; ++i) {
            const size_t base = i * N;
            for (size_t j = 0; j < N; ++j) {
                double sum = 0.0;
                if (i > 0)          sum += in[base - N];
                if (i + 1 < N)      sum += in[base + N];
                if (j > 0)          sum += in[base - 1];
                if (j + 1 < N)      sum += in[base + 1];
                sum += in[base];
                out[base + j] = sum * 0.2;   // 1/5
            }
        }
        return;
    }

    size_t i, j;

    /* Parallelise over rows and columns simultaneously. */
    #pragma omp parallel for collapse(2) schedule(static)
    for (i = 0; i < N; ++i) {
        const size_t base = i * N;
        /* Get pointers to the previous, current and next rows. */
        const double *prev = (i == 0)      ? nullptr : in + (i - 1) * N;
        const double *curr = in + base;
        const double *next = (i + 1 == N)  ? nullptr : in + (i + 1) * N;

        /* Process the first column (j = 0) – special treatment for the left border */
        {
            double sum = curr[0];
            if (prev) sum += prev[0];
            if (next) sum += next[0];
            if (curr[1]) sum += curr[1];
            out[base] = sum * 0.2;
        }

        /* Process an interior chunk that can be unrolled by 4. */
        for (j = 1; j + 3 < N; j += 4) {
            const double c0 = curr[j];
            const double c1 = curr[j + 1];
            const double c2 = curr[j + 2];
            const double c3 = curr[j + 3];

            double s0 = c0 + ((prev) ? prev[j] : 0.0) + ((next) ? next[j] : 0.0);
            double s1 = c1 + ((prev) ? prev[j + 1] : 0.0) + ((next) ? next[j + 1] : 0.0);
            double s2 = c2 + ((prev) ? prev[j + 2] : 0.0) + ((next) ? next[j + 2] : 0.0);
            double s3 = c3 + ((prev) ? prev[j + 3] : 0.0) + ((next) ? next[j + 3] : 0.0);

            s0 += curr[j - 1];
            s1 += curr[j + 0];
            s2 += curr[j + 1];
            s3 += curr[j + 2];

            out[base + j]     = s0 * 0.2;
            out[base + j + 1] = s1 * 0.2;
            out[base + j + 2] = s2 * 0.2;
            out[base + j + 3] = s3 * 0.2;
        }

        /* Handle the remaining columns (tail) */
        for (; j < N; ++j) {
            double sum = curr[j];
            if (prev) sum += prev[j];
            if (next) sum += next[j];
            if (j > 0) sum += curr[j - 1];
            if (j + 1 < N) sum += curr[j + 1];
            out[base + j] = sum * 0.2;
        }
    }
}
